    @Override
    public List<Check<TskTaskRecord>> getChecks() {
        return Arrays.asList(
            Internal.createCheck(this, DSL.name("ck_tsk_assignee_policy_ref_workflow_context"), "(((assignee_policy_ref IS NULL) OR (workflow_definition_version_id IS NOT NULL)))", true),
            Internal.createCheck(this, DSL.name("ck_tsk_automated_claim"), "(((((task_kind)::text = 'AUTOMATED'::text) AND ((((status)::text = 'CLAIMED'::text) AND (claim_owner IS NOT NULL) AND (claim_until IS NOT NULL) AND (current_attempt_id IS NOT NULL)) OR (((status)::text <> 'CLAIMED'::text) AND (claim_owner IS NULL) AND (claim_until IS NULL) AND (current_attempt_id IS NULL)))) OR (((task_kind)::text = 'HUMAN'::text) AND (claim_owner IS NULL) AND (claim_until IS NULL) AND (current_attempt_id IS NULL))))", true),
            Internal.createCheck(this, DSL.name("ck_tsk_configuration_bundle_digest"), "(((configuration_bundle_digest IS NULL) OR (configuration_bundle_digest ~ '^[0-9a-f]{64}$'::text)))", true),
            Internal.createCheck(this, DSL.name("ck_tsk_dispatch_policy_ref_workflow_context"), "(((dispatch_policy_ref IS NULL) OR (workflow_definition_version_id IS NOT NULL)))", true),
            Internal.createCheck(this, DSL.name("ck_tsk_form_ref_workflow_context"), "(((form_ref IS NULL) OR (workflow_definition_version_id IS NOT NULL)))", true),
            Internal.createCheck(this, DSL.name("ck_tsk_human_completion"), "(((((task_kind)::text = 'HUMAN'::text) AND ((status)::text = 'COMPLETED'::text) AND (completed_at IS NOT NULL) AND (result_ref IS NOT NULL) AND (result_digest IS NOT NULL)) OR (((task_kind)::text <> 'HUMAN'::text) OR ((status)::text <> 'COMPLETED'::text))))", true),
            Internal.createCheck(this, DSL.name("ck_tsk_human_lifecycle"), "(((((task_kind)::text = 'AUTOMATED'::text) AND (claimed_by IS NULL) AND (claimed_at IS NULL) AND (started_at IS NULL)) OR (((task_kind)::text = 'HUMAN'::text) AND ((((status)::text = 'READY'::text) AND (claimed_by IS NULL) AND (claimed_at IS NULL) AND (started_at IS NULL)) OR (((status)::text = 'CLAIMED'::text) AND (claimed_by IS NOT NULL) AND (claimed_at IS NOT NULL) AND (started_at IS NULL)) OR (((status)::text = ANY ((ARRAY['RUNNING'::character varying, 'COMPLETED'::character varying])::text[])) AND (claimed_by IS NOT NULL) AND (claimed_at IS NOT NULL) AND (started_at IS NOT NULL)) OR ((status)::text = ANY ((ARRAY['MANUAL_INTERVENTION'::character varying, 'CANCELLED'::character varying])::text[]))))))", true),
            Internal.createCheck(this, DSL.name("ck_tsk_input_version_refs"), "(((input_version_refs IS NULL) OR (jsonb_typeof(input_version_refs) = 'array'::text)))", true),
            Internal.createCheck(this, DSL.name("ck_tsk_result_digest"), "(((result_digest IS NULL) OR (result_digest ~ '^[0-9a-f]{64}$'::text)))", true),
            Internal.createCheck(this, DSL.name("ck_tsk_rule_ref_workflow_context"), "(((rule_ref IS NULL) OR (workflow_definition_version_id IS NOT NULL)))", true),
            Internal.createCheck(this, DSL.name("ck_tsk_sla_ref_workflow_context"), "(((sla_ref IS NULL) OR (workflow_definition_version_id IS NOT NULL)))", true),
            Internal.createCheck(this, DSL.name("ck_tsk_stage_code"), "(((stage_code IS NULL) OR ((stage_code)::text ~ '^[A-Z][A-Z0-9_]*$'::text)))", true),
            Internal.createCheck(this, DSL.name("ck_tsk_task_attempts"), "(((attempt_count >= 0) AND (max_attempts > 0) AND (attempt_count <= max_attempts)))", true),
            Internal.createCheck(this, DSL.name("ck_tsk_task_cancellation_evidence"), "(((((status)::text = 'CANCELLED'::text) AND (cancelled_at IS NOT NULL) AND (cancellation_reason_code IS NOT NULL) AND (cancellation_source_event_id IS NOT NULL)) OR (((status)::text <> 'CANCELLED'::text) AND (cancelled_at IS NULL) AND (cancellation_reason_code IS NULL) AND (cancellation_source_event_id IS NULL))))", true),
            Internal.createCheck(this, DSL.name("ck_tsk_task_kind"), "(((task_kind)::text = ANY ((ARRAY['AUTOMATED'::character varying, 'HUMAN'::character varying])::text[])))", true),
            Internal.createCheck(this, DSL.name("ck_tsk_task_priority"), "(((priority >= 0) AND (priority <= 1000)))", true),
            Internal.createCheck(this, DSL.name("ck_tsk_task_status"), "(((status)::text = ANY ((ARRAY['READY'::character varying, 'PENDING'::character varying, 'CLAIMED'::character varying, 'RUNNING'::character varying, 'RETRY_WAIT'::character varying, 'SUCCEEDED'::character varying, 'COMPLETED'::character varying, 'MANUAL_INTERVENTION'::character varying, 'CANCELLED'::character varying])::text[])))", true),
            Internal.createCheck(this, DSL.name("ck_tsk_workflow_context_complete"), "((((project_id IS NULL) AND (work_order_id IS NULL) AND (workflow_instance_id IS NULL) AND (stage_instance_id IS NULL) AND (workflow_node_instance_id IS NULL) AND (workflow_node_id IS NULL) AND (workflow_definition_version_id IS NULL) AND (workflow_definition_digest IS NULL) AND (configuration_bundle_id IS NULL) AND (configuration_bundle_digest IS NULL) AND (stage_code IS NULL)) OR ((project_id IS NOT NULL) AND (work_order_id IS NOT NULL) AND (workflow_instance_id IS NOT NULL) AND (stage_instance_id IS NOT NULL) AND (workflow_node_instance_id IS NOT NULL) AND (workflow_node_id IS NOT NULL) AND (workflow_definition_version_id IS NOT NULL) AND (workflow_definition_digest IS NOT NULL) AND (configuration_bundle_id IS NOT NULL) AND (configuration_bundle_digest IS NOT NULL) AND (stage_code IS NOT NULL))))", true),
            Internal.createCheck(this, DSL.name("ck_tsk_workflow_definition_digest"), "(((workflow_definition_digest IS NULL) OR (workflow_definition_digest ~ '^[0-9a-f]{64}$'::text)))", true)
        );
    }

